// === src/pages/ProductManager.js ===
import React, { useState } from 'react';
import './ProductManager.css';
import ProductCard from '../components/ProductCard';

const categories = ['All', 'Plants', 'Flowers', 'Decor', 'Pots'];

const ProductManager = () => {
  const [products, setProducts] = useState(() => {
    const stored = localStorage.getItem('products');
    return stored ? JSON.parse(stored) : [];
  });

  const [formData, setFormData] = useState({ name: '', price: '', description: '', image: '', category: 'Plants' });
  const [editingIndex, setEditingIndex] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [categoryFilter, setCategoryFilter] = useState('All');

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    const reader = new FileReader();

    reader.onloadend = () => {
      setFormData({ ...formData, image: reader.result });
    };

    if (file) {
      reader.readAsDataURL(file);
    }
  };

  const handleAddOrUpdate = (e) => {
    e.preventDefault();
    if (!formData.name || !formData.price) return alert('Please fill in all fields');

    let updated;
    if (editingIndex !== null) {
      updated = [...products];
      updated[editingIndex] = formData;
      setEditingIndex(null);
    } else {
      updated = [...products, formData];
    }

    setProducts(updated);
    localStorage.setItem('products', JSON.stringify(updated));
    setFormData({ name: '', price: '', description: '', image: '', category: 'Plants' });
  };

  const handleEdit = (index) => {
    setFormData(products[index]);
    setEditingIndex(index);
  };

  const handleDelete = (index) => {
    const updated = products.filter((_, i) => i !== index);
    setProducts(updated);
    localStorage.setItem('products', JSON.stringify(updated));

    if (editingIndex === index) {
      setFormData({ name: '', price: '', description: '', image: '', category: 'Plants' });
      setEditingIndex(null);
    }
  };

  const filteredProducts = products
    .filter((p) => categoryFilter === 'All' || p.category === categoryFilter)
    .filter((p) => p.name.toLowerCase().includes(searchTerm));

  return (
    <div className="product-manager">
      <h2>🛒 Manage Products</h2>

      <input
        type="text"
        placeholder="Search products..."
        className="search-input"
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value.toLowerCase())}
      />

      <select
        value={categoryFilter}
        onChange={(e) => setCategoryFilter(e.target.value)}
        className="filter-dropdown"
      >
        {categories.map((cat) => (
          <option key={cat} value={cat}>{cat}</option>
        ))}
      </select>

      <form onSubmit={handleAddOrUpdate} className="product-form">
        <input name="name" placeholder="Product Name" value={formData.name} onChange={handleChange} />
        <input name="price" placeholder="Price" value={formData.price} onChange={handleChange} />
        <textarea name="description" placeholder="Description" value={formData.description} onChange={handleChange} />
        <select name="category" value={formData.category} onChange={handleChange}>
          {categories.slice(1).map((cat) => (
            <option key={cat} value={cat}>{cat}</option>
          ))}
        </select>
        <input type="file" accept="image/*" onChange={handleImageUpload} />
        {formData.image && <img src={formData.image} alt="Preview" className="preview-img" />}
        <button type="submit">{editingIndex !== null ? 'Update' : 'Add'} Product</button>
      </form>

      <div className="product-list">
        {filteredProducts.map((p, idx) => (
          <ProductCard
            key={idx}
            product={p}
            onEdit={() => handleEdit(idx)}
            onDelete={() => handleDelete(idx)}
          />
        ))}
      </div>
    </div>
  );
};

export default ProductManager;
